#include <stdio.h>
#include <string.h>
int main() {
    int n;
    scanf("%d", &n);
    char words[n][11];
    for (int i = 0; i < n; i++) {
        scanf("%s", words[i]);
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (strlen(words[i]) != strlen(words[j])) continue;
            int match = 1;
            for (int k = 0; k < strlen(words[i]); k++) {
                if (strchr(words[j], words[i][k]) == NULL) {
                    match = 0;
                    break;
                }
            }
            if (match) count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

