#include <iostream>
#include <string>
using namespace std;
int main() {
    int n;
    cin >> n;
    string words[n];
    for (int i = 0; i < n; i++) {
        cin >> words[i];
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (words[i].length() != words[j].length()) continue;
            string temp = words[j];
            bool match = true;
            for (char c : words[i]) {
                if (temp.find(c) == string::npos) {
                    match = false;
                    break;
                } else {
                    temp.erase(temp.find(c), 1);
                }
            }
            if (match) count++;
        }
    }
    cout << count << endl;
    return 0;
}

