const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let words = [];
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
    } else {
        words.push(line);
    }
    i++;
    if (i > n) {
        let count = 0;
        for (let j = 0; j < n; j++) {
            for (let k = j + 1; k < n; k++) {
                if (words[j].length != words[k].length) continue;
                let temp = words[k].split('');
                let match = true;
                for (let l = 0; l < words[j].length; l++) {
                    let index = temp.indexOf(words[j][l]);
                    if (index == -1) {
                        match = false;
                        break;
                    } else {
                        temp.splice(index, 1);
                    }
                }
                if (match) count++;
            }
        }
        console.log(count);
        readline.close();
    }
});
